269.     /// <returns>true if the string contains only ASCII alphanumeric characters; otherwise, false.</returns>
270.     public static bool IsAsciiAlphanumeric(this string input)
271.     {
272.         if (string.IsNullOrEmpty(input))
273.         {
274.             return false;
275.         }
276. 
