288.     /// <summary>
289.     /// Returns the number of words in a string, splitting on whitespace and common delimiters.
290.     /// </summary>
291.     /// <param name="input">The string to count words in.</param>
292.     /// <returns>The number of words found.</returns>
293.     public static int WordCount(this string input)
294.     {
295.         if (string.IsNullOrWhiteSpace(input))
296.         {
297.             return 0;
298.         }
299. 
300.         var count = 0;
301.         var inWord = false;
302.         foreach (var c in input)
303.         {
304.             if (char.IsLetterOrDigit(c))
305.             {
306.                 if (!inWord)
307.                 {
308.                     count++;
309.                     inWord = true;
310.                 }
311.             }
312.             else
313.             {
314.                 inWord = false;
315.             }
316.         }
317. 
318.         return count;
319.     }
320. }
