     /// <returns>The number of words found.</returns>
     public static int WordCount(this string input)
     {
         if (string.IsNullOrWhiteSpace(input))
         {
             return 0;
         }

         var count = 0;
         var inWord = false;
         foreach (var c in input)
         {
             if (char.IsLetterOrDigit(c))
             {
                 if (!inWord)
                 {
                     count++;
                     inWord = true;
                 }
             }
             else
             {
                 inWord = false;
             }
         }

